package ru.memearena.tournament.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="tournament_match") public class TournamentMatch{ @Id public UUID id; @Column(name="tournament_id") public UUID tournamentId; @Column(name="round_number") public int roundNumber; @Column(name="match_number") public int matchNumber; @Column(name="left_meme_id") public UUID leftMemeId; @Column(name="right_meme_id") public UUID rightMemeId; @Column(name="winner_meme_id") public UUID winnerMemeId; @Column(name="left_votes") public long leftVotes; @Column(name="right_votes") public long rightVotes; @Enumerated(EnumType.STRING) public TournamentMatchStatus status; @Column(name="starts_at") public Instant startsAt; @Column(name="ends_at") public Instant endsAt; @Column(name="completed_at") public Instant completedAt; @Column(name="created_at") public Instant createdAt; @Column(name="updated_at") public Instant updatedAt; protected TournamentMatch(){} public TournamentMatch(UUID id,UUID t,int r,int n,UUID l,UUID ri,TournamentMatchStatus st,Instant s,Instant e,Instant now){this.id=id;this.tournamentId=t;this.roundNumber=r;this.matchNumber=n;this.leftMemeId=l;this.rightMemeId=ri;this.status=st;this.startsAt=s;this.endsAt=e;this.createdAt=now;this.updatedAt=now;} public UUID getId(){return id;} public UUID getLeftMemeId(){return leftMemeId;} public UUID getRightMemeId(){return rightMemeId;} }
